import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [extractedText, setExtractedText] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [questionType, setQuestionType] = useState('subjective');
  const [questionText, setQuestionText] = useState('');
  const [answerText, setAnswerText] = useState('');
  const [rubricsText, setRubricsText] = useState('');
  const [questionMsg, setQuestionMsg] = useState('');

  // Load Puter script
  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://js.puter.com/v2/';
    script.async = true;
    document.body.appendChild(script);
  }, []);

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      setFile(selectedFile);
      setError('');
    }
  };

  const handleUpload = async (e) => {
    e.preventDefault();

    if (!file) {
      setError('Please select a file first');
      return;
    }

    setLoading(true);
    setError('');
    setExtractedText('');
    setProcessedText('');

    try {
      // Step 1: Upload file to backend
      const formData = new FormData();
      formData.append('file', file);

      const uploadResponse = await fetch('http://localhost:8000/ocr', {
        method: 'POST',
        body: formData,
      });

      if (!uploadResponse.ok) {
        throw new Error('Failed to upload file');
      }

      const uploadData = await uploadResponse.json();

      if (uploadData.error) {
        throw new Error(uploadData.error);
      }

      const dataUrl = uploadData.data_url;

      // Step 2: Use Puter chat API with GPT-5 nano for image analysis
      if (!window.puter) {
        throw new Error('Puter library not loaded. Please check your internet connection.');
      }

      let extractedTextContent = '';

      try {
        extractedTextContent = await window.puter.ai.chat(
          'Extract all the text from this image and return it as a paragraph. Only return the text, nothing else.',
          dataUrl,
          { model: 'gpt-5-nano' }
        );
      } catch (puterError) {
        throw new Error(`Puter chat API failed: ${puterError.message}`);
      }

      setExtractedText(extractedTextContent);

      // Note: removed client-side preprocess display — backend still exposes /preprocess

    } catch (err) {
      setError(`Error: ${err.message}`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container">
      <header className="header">
        <h1>AI-Assisted Exam Evaluator</h1>
        <p>Upload exam answer sheets for OCR and preprocessing</p>
      </header>

      <main className="main">
        <section className="upload-section">
          <form onSubmit={handleUpload}>
            <div className="file-input-wrapper">
              <label htmlFor="file-input" className="file-label">
                Choose Image or PDF
              </label>
              <input
                id="file-input"
                type="file"
                onChange={handleFileChange}
                accept="image/*,.pdf"
                disabled={loading}
              />
              {file && <p className="file-name">Selected: {file.name}</p>}
            </div>

            <button 
              type="submit" 
              className="upload-btn"
              disabled={loading || !file}
            >
              {loading ? 'Processing...' : 'Upload & Process'}
            </button>
          </form>

          {error && <div className="error-message">{error}</div>}
        </section>

        <section className="results-section">
          <div className="text-area-wrapper">
            <label htmlFor="extracted">Extracted Text (Puter AI Chat)</label>
            <textarea
              id="extracted"
              value={extractedText}
              readOnly
              placeholder="OCR extracted text will appear here..."
            />
          </div>

          {/* Question Dashboard */}
          <section className="question-dashboard">
            <h2>Question Upload Dashboard</h2>
            <form onSubmit={async (e) => {
              e.preventDefault();
              setQuestionMsg('');
              try {
                const payload = {
                  question: String(questionText),
                  answer: questionType === 'subjective' ? String(answerText) : String(rubricsText),
                  q_type: questionType
                };

                const resp = await fetch('http://localhost:8000/questions', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify(payload)
                });

                const data = await resp.json();
                if (data.status === 'success') {
                  setQuestionMsg('Saved successfully');
                  setQuestionText('');
                  setAnswerText('');
                  setRubricsText('');
                } else {
                  setQuestionMsg('Save failed: ' + (data.message || 'unknown'));
                }
              } catch (err) {
                setQuestionMsg('Error: ' + err.message);
              }
            }}>
              <div className="form-row">
                <label>Type</label>
                <select value={questionType} onChange={(e) => setQuestionType(e.target.value)}>
                  <option value="subjective">Subjective</option>
                  <option value="creative">Creative</option>
                </select>
              </div>

              <div className="form-row">
                <label>Question (text)</label>
                <textarea value={questionText} onChange={(e) => setQuestionText(e.target.value)} required />
              </div>

              {questionType === 'subjective' ? (
                <div className="form-row">
                  <label>Answer (paragraph)</label>
                  <textarea value={answerText} onChange={(e) => setAnswerText(e.target.value)} placeholder="Enter expected paragraph answer" required />
                </div>
              ) : (
                <div className="form-row">
                  <label>Rubrics (one per line)</label>
                  <textarea value={rubricsText} onChange={(e) => setRubricsText(e.target.value)} placeholder="Enter rubrics, one per line" />
                </div>
              )}

              <button type="submit" className="upload-btn">Save Question</button>
              {questionMsg && <div className="info-message">{questionMsg}</div>}
            </form>
          </section>
        </section>
      </main>

      <footer className="footer">
        <p>Phase: Upload → Puter Chat GPT-5 nano → Text Preprocessing | Ready for subjective evaluation</p>
      </footer>
    </div>
  );
}

export default App;
